// Navbar.js - COMPLETE CORRECTED VERSION
import React, { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { useNavigate } from "react-router-dom";
import { useCart } from "../pages/CartContext";
import { useAuth } from "../context/AuthContext";
import "../styles/Navbar.css";

// Sample product data for search
const searchProducts = [
  { id: 1, title: "Tropical Breeze Dress", price: "$89", category: "dress", collection: "summer", img: "https://images.unsplash.com/photo-1594633312681-425c7b97ccd1?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=1000&q=80" },
  { id: 2, title: "Weekend Comfort Top", price: "$45", category: "top", collection: "casual", img: "https://plus.unsplash.com/premium_photo-1693242804347-38b4382b3c4d?ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&q=80&w=987" },
  { id: 3, title: "Diamond Solitaire Necklace", price: "$299", category: "necklace", collection: "jewelry", img: "https://images.unsplash.com/photo-1605100804763-247f67b3557e?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=1000&q=80" },
  { id: 4, title: "Ocean Wave Skirt", price: "$65", category: "skirt", collection: "summer", img: "https://images.unsplash.com/photo-1441986300917-64674bd600d8?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=1000&q=80" },
  { id: 5, title: "Relaxed Fit Jeans", price: "$65", category: "pants", collection: "casual", img: "https://plus.unsplash.com/premium_photo-1708276238428-4131c56a5487?ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&q=80&w=1035" },
  { id: 6, title: "Summer Breeze Romper", price: "$78", category: "romper", collection: "summer", img: "https://images.unsplash.com/photo-1529903384028-929ae5dccdf1?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=1000&q=80" },
  { id: 7, title: "Sunset Glow Top", price: "$45", category: "top", collection: "summer", img: "https://images.unsplash.com/photo-1594223274512-ad4803739b7c?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=1000&q=80" },
  { id: 8, title: "Beach Day Shorts", price: "$55", category: "shorts", collection: "summer", img: "https://images.unsplash.com/photo-1541099649105-f69ad21f3246?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=1000&q=80" },
  { id: 9, title: "Tropical Maxi Dress", price: "$95", category: "dress", collection: "summer", img: "https://images.unsplash.com/photo-1582738509941-360b28c941ea?ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&q=80&w=985" },
  { id: 10, title: "Cozy Sweater", price: "$78", category: "sweater", collection: "casual", img: "https://images.unsplash.com/photo-1434389677669-e08b4cac3105?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=1000&q=80" },
  { id: 11, title: "Pearl Drop Earrings", price: "$159", category: "earrings", collection: "jewelry", img: "https://images.unsplash.com/photo-1535632066927-ab7c9ab60908?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=1000&q=80" },
  { id: 12, title: "Stackable Gold Rings", price: "$89", category: "rings", collection: "jewelry", img: "https://images.unsplash.com/photo-1515562141207-7a88fb7ce338?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=1000&q=80" }
];

const Navbar = () => {
  const [scrolled, setScrolled] = useState(false);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const [searchOpen, setSearchOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");
  const [searchResults, setSearchResults] = useState([]);
  const [cartOpen, setCartOpen] = useState(false);
  const [profileOpen, setProfileOpen] = useState(false);

  const navigate = useNavigate();
  const { cart, getCartCount, removeFromCart, updateQuantity, getCartTotal } = useCart();
  const { user, isAuthenticated, logout } = useAuth();

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 50);
    };

    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  // Search functionality
  useEffect(() => {
    if (searchQuery.trim() === "") {
      setSearchResults([]);
      return;
    }

    const filtered = searchProducts.filter(product =>
      product.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
      product.category.toLowerCase().includes(searchQuery.toLowerCase())
    );
    setSearchResults(filtered);
  }, [searchQuery]);

  const scrollToSection = (sectionId) => {
    const element = document.getElementById(sectionId);
    if (element) {
      element.scrollIntoView({ behavior: 'smooth' });
    }
    setMobileMenuOpen(false);
  };

  const handleSearchToggle = () => {
    setSearchOpen(!searchOpen);
    if (searchOpen) {
      setSearchQuery("");
      setSearchResults([]);
    }
    setCartOpen(false);
    setProfileOpen(false);
  };

  const handleSearchSubmit = (e) => {
    e.preventDefault();
    if (searchQuery.trim()) {
      const firstResult = searchResults[0];
      if (firstResult) {
        navigate(`/${firstResult.collection}-collection`);
      }
      setSearchOpen(false);
      setSearchQuery("");
    }
  };

  const handleProductClick = (product) => {
    navigate(`/${product.collection}-collection`);
    setSearchOpen(false);
    setSearchQuery("");
  };

  const handleSearchChange = (e) => {
    setSearchQuery(e.target.value);
  };

  const handleCartToggle = () => {
    setCartOpen(!cartOpen);
    setSearchOpen(false);
    setProfileOpen(false);
  };

  const handleProfileToggle = () => {
    setProfileOpen(!profileOpen);
    setSearchOpen(false);
    setCartOpen(false);
  };

  const handleIncreaseQuantity = (item) => {
    updateQuantity(item, item.quantity + 1);
  };

  const handleDecreaseQuantity = (item) => {
    if (item.quantity > 1) {
      updateQuantity(item, item.quantity - 1);
    } else {
      removeFromCart(item);
    }
  };

  const handleRemoveItem = (item) => {
    removeFromCart(item);
  };

  const handleCheckout = () => {
    setCartOpen(false);
    alert('Proceeding to checkout! Total: $' + getCartTotal().toFixed(2));
  };

  const handleLogin = () => {
    setProfileOpen(false);
    navigate('/login');
  };

  const handleSignup = () => {
    setProfileOpen(false);
    navigate('/signup');
  };

  const handleLogout = () => {
    logout();
    setProfileOpen(false);
    navigate('/');
  };

  const handleProfile = () => {
    setProfileOpen(false);
    navigate('/profile');
  };

  // Close dropdowns when clicking outside
  useEffect(() => {
    const handleClickOutside = (event) => {
      if (searchOpen && !event.target.closest('.nav-search-container')) {
        setSearchOpen(false);
      }
      if (cartOpen && !event.target.closest('.nav-cart-container')) {
        setCartOpen(false);
      }
      if (profileOpen && !event.target.closest('.nav-profile-container')) {
        setProfileOpen(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, [searchOpen, cartOpen, profileOpen]);

  return (
    <motion.nav
      className={`nav-main ${scrolled ? "scrolled" : ""}`}
      initial={{ y: -80 }}
      animate={{ y: 0 }}
      transition={{ duration: 0.8 }}
    >
      <div className="nav-main-container">
        <motion.h1 
          className="nav-logo"
          whileHover={{ scale: 1.05 }}
          onClick={() => scrollToSection('home')}
          style={{ cursor: 'pointer' }}
        >
          AURI
        </motion.h1>

        <ul className={`nav-main-links ${mobileMenuOpen ? "active" : ""}`}>
          <li><a href="#home" onClick={(e) => { e.preventDefault(); scrollToSection('home'); }}>Home</a></li>
          <li><a href="#collection" onClick={(e) => { e.preventDefault(); scrollToSection('collection'); }}>Collection</a></li>
          <li><a href="#about" onClick={(e) => { e.preventDefault(); scrollToSection('about'); }}>About</a></li>
          <li><a href="#contact" onClick={(e) => { e.preventDefault(); scrollToSection('contact'); }}>Contact</a></li>
        </ul>

        <div className="nav-main-actions">
          {/* Search Button and Search Bar */}
          <div className="nav-search-container">
            <button 
              className={`nav-search-btn ${searchOpen ? "active" : ""}`}
              onClick={handleSearchToggle}
            >
              <i className="fas fa-search"></i>
            </button>

            <AnimatePresence>
              {searchOpen && (
                <motion.div
                  className="nav-search-bar"
                  initial={{ opacity: 0, y: -10 }}
                  animate={{ opacity: 1, y: 0 }}
                  exit={{ opacity: 0, y: -10 }}
                  transition={{ duration: 0.3 }}
                >
                  <form onSubmit={handleSearchSubmit}>
                    <input
                      type="text"
                      placeholder="Search products..."
                      value={searchQuery}
                      onChange={handleSearchChange}
                      autoFocus
                      className="nav-search-input"
                    />
                    <button type="submit" className="nav-search-submit">
                      <i className="fas fa-arrow-right"></i>
                    </button>
                  </form>

                  {/* Search Results Dropdown */}
                  {searchResults.length > 0 && (
                    <motion.div
                      className="nav-search-results"
                      initial={{ opacity: 0 }}
                      animate={{ opacity: 1 }}
                      transition={{ duration: 0.2 }}
                    >
                      {searchResults.slice(0, 5).map((product) => (
                        <div
                          key={product.id}
                          className="nav-search-result-item"
                          onClick={() => handleProductClick(product)}
                        >
                          <img src={product.img} alt={product.title} />
                          <div className="nav-result-info">
                            <h4>{product.title}</h4>
                            <p>{product.price} • {product.category}</p>
                          </div>
                        </div>
                      ))}
                    </motion.div>
                  )}

                  {/* No Results Message */}
                  {searchQuery && searchResults.length === 0 && (
                    <motion.div
                      className="nav-search-no-results"
                      initial={{ opacity: 0 }}
                      animate={{ opacity: 1 }}
                    >
                      No products found for "{searchQuery}"
                    </motion.div>
                  )}
                </motion.div>
              )}
            </AnimatePresence>
          </div>

          {/* Cart Button with Dropdown */}
          <div className="nav-cart-container">
            <button 
              className={`nav-cart-btn ${cartOpen ? "active" : ""}`}
              onClick={handleCartToggle}
            >
              <i className="fas fa-shopping-bag"></i>
              <span className="nav-cart-count">{getCartCount()}</span>
            </button>

            <AnimatePresence>
              {cartOpen && (
                <motion.div
                  className="nav-cart-dropdown"
                  initial={{ opacity: 0, y: -10 }}
                  animate={{ opacity: 1, y: 0 }}
                  exit={{ opacity: 0, y: -10 }}
                  transition={{ duration: 0.3 }}
                >
                  <div className="nav-cart-header">
                    <h3>Shopping Cart ({getCartCount()} items)</h3>
                  </div>

                  <div className="nav-cart-items">
                    {cart.items.length === 0 ? (
                      <div className="nav-empty-cart">
                        <p>Your cart is empty</p>
                      </div>
                    ) : (
                      <>
                        {cart.items.map((item) => (
                          <div key={`${item.id}-${item.selectedSize}-${item.selectedColor}`} className="nav-cart-item">
                            <img src={item.img} alt={item.title} />
                            <div className="nav-cart-item-info">
                              <h4>{item.title}</h4>
                              <p>{item.selectedSize} • {item.selectedColor}</p>
                              <p className="nav-cart-item-price">{item.price}</p>
                            </div>
                            <div className="nav-cart-item-actions">
                              <div className="nav-quantity-controls">
                                <button 
                                  onClick={() => handleDecreaseQuantity(item)}
                                  disabled={item.quantity <= 1}
                                >
                                  -
                                </button>
                                <span>{item.quantity}</span>
                                <button onClick={() => handleIncreaseQuantity(item)}>
                                  +
                                </button>
                              </div>
                              <button 
                                className="nav-remove-btn"
                                onClick={() => handleRemoveItem(item)}
                                title="Remove item"
                              >
                                ×
                              </button>
                            </div>
                          </div>
                        ))}
                      </>
                    )}
                  </div>

                  {cart.items.length > 0 && (
                    <div className="nav-cart-footer">
                      <div className="nav-cart-total">
                        <strong>Total: ${getCartTotal().toFixed(2)}</strong>
                      </div>
                      <button className="nav-checkout-btn" onClick={handleCheckout}>
                        Proceed to Checkout
                      </button>
                    </div>
                  )}
                </motion.div>
              )}
            </AnimatePresence>
          </div>

          {/* Profile Button with Dropdown */}
          <div className="nav-profile-container">
            <button 
              className={`nav-profile-btn ${profileOpen ? "active" : ""}`}
              onClick={handleProfileToggle}
            >
              <i className="fas fa-user"></i>
            </button>

            <AnimatePresence>
              {profileOpen && (
                <motion.div
                  className="nav-profile-dropdown"
                  initial={{ opacity: 0, y: -10 }}
                  animate={{ opacity: 1, y: 0 }}
                  exit={{ opacity: 0, y: -10 }}
                  transition={{ duration: 0.3 }}
                >
                  {isAuthenticated ? (
                    <>
                      <div className="nav-profile-header">
                        <h3>Welcome, {user?.firstName || 'User'}!</h3>
                        <p>{user?.email}</p>
                      </div>
                      <div className="nav-profile-menu">
                        <button className="nav-profile-item" onClick={handleProfile}>
                          <i className="fas fa-user-circle"></i>
                          My Profile
                        </button>
                        <button className="nav-profile-item nav-profile-logout" onClick={handleLogout}>
                          <i className="fas fa-sign-out-alt"></i>
                          Logout
                        </button>
                      </div>
                    </>
                  ) : (
                    <div className="nav-profile-menu">
                      <button className="nav-profile-item" onClick={handleLogin}>
                        <i className="fas fa-sign-in-alt"></i>
                        Login
                      </button>
                      <button className="nav-profile-item" onClick={handleSignup}>
                        <i className="fas fa-user-plus"></i>
                        Sign Up
                      </button>
                    </div>
                  )}
                </motion.div>
              )}
            </AnimatePresence>
          </div>

          <button 
            className={`nav-mobile-menu-btn ${mobileMenuOpen ? "active" : ""}`}
            onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
          >
            <span></span>
            <span></span>
            <span></span>
          </button>
        </div>
      </div>
    </motion.nav>
  );
};

export default Navbar;
